// Extract and enrich alert metadata
const alert = $input.first().json;
const enrichment = {
  team: alert.labels?.team || 'ops-default',
  service: alert.labels?.service || 'unknown',
  owner_email: alert.labels?.owner_email || 'ops@company.com',
  pagerduty_service_id: alert.labels?.pagerduty_id || null,
  escalation_policy: alert.severity === 'CRITICAL' ? 'urgent' : 'standard',
  auto_remediate: alert.labels?.auto_remediate === 'true',
  tags: (alert.labels?.tags || '').split(',').map(t => t.trim()),
  cmdb_lookup: {
    service_id: 'svc_' + (alert.labels?.service || 'unknown'),
    app_tier: alert.labels?.tier || 'backend',
    environment: alert.labels?.env || 'production'
  }
};

return {
  ...alert,
  enrichment_data: enrichment,
  enrichment_timestamp: new Date().toISOString()
};

// Merge CMDB data into enrichment
const enriched = $input.first().json;
const cmdbData = $input.last().json || {};

return {
  ...enriched,
  enrichment_data: {
    ...enriched.enrichment_data,
    cmdb_data: {
      service_owner: cmdbData.owner_name,
      service_tier: cmdbData.tier,
      dependencies: cmdbData.dependencies || [],
      oncall_rotation: cmdbData.oncall_engineer || null
    }
  }
};
